class evalfinancial_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('evalfinancial page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$summary = $fs->addElement('text', 'summary', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Summary (4)' )
;
		$idevalfinancial = $fs->addElement('text', 'idevalfinancial', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$ownerearnings = $fs->addElement('text', 'ownerearnings', array('size' => 10, 'maxlength' => 10) )
			->setLabel( 'Owners Earnings' )
;
		$f_date = date("Y-m-d H:i:s" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'lasteval' => $f_date ) ) );
		$lasteval = $fs->addElement('text', 'lasteval', array('size' => 16, 'maxlength' => 16) )
			->setLabel( 'Evaluation Time' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
;
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'user' => $_SERVER['PHP_AUTH_USER'] ) ) );
		$user = $fs->addElement('text', 'user', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Evaluating User' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'user Field Required' );
		$debtratio = $fs->addElement('text', 'debtratio', array('size' => 10, 'maxlength' => 10) )
			->setLabel( 'Debt to Equity Ratio' )
;
		$acceptabledebt = $fs->addElement('text', 'acceptabledebt', array('size' => 10, 'maxlength' => 10) )
			->setLabel( 'Acceptable Debt Level' )
;
	}
}
